57	static struct qemu_plugin_register *find_reg(GArray *regs, const char *name)
58	{
59	    for (guint i = 0; i < regs->len; i++) {
60	        qemu_plugin_reg_descriptor *rd =
61	            &g_array_index(regs, qemu_plugin_reg_descriptor, i);
62	        if (g_ascii_strcasecmp(rd->name, name) == 0) {
63	            return rd->handle;
64	        }
65	    }
66	    return NULL;
67	}
