69	// Lazily resolves register handles. The plugin's vcpu_init runs before
70	// QEMU has registered the dynamic gdb coprocessors (FPU, virtual, csr,
71	// vector), so qemu_plugin_get_registers() returns only the 33 core CPU
72	// regs at that moment. By the time the entry trigger fires, all dynamic
73	// features are registered and a fresh call returns the full list.
74	static void resolve_handles(VcpuRegs *v)
75	{
76	    g_autoptr(GArray) regs = qemu_plugin_get_registers();
77	    for (int i = 0; i < 32; i++) {
78	        v->gpr[i] = find_reg(regs, hybrid_gpr_names[i]);
79	        v->fpr[i] = find_reg(regs, hybrid_fpr_names[i]);
80	    }
81	    v->pc = find_reg(regs, "pc");
82	
83	    v->mstatus  = find_reg(regs, "mstatus");
84	    v->mepc     = find_reg(regs, "mepc");
85	    v->mtvec    = find_reg(regs, "mtvec");
86	    v->mcause   = find_reg(regs, "mcause");
87	    v->mtval    = find_reg(regs, "mtval");
88	    v->mscratch = find_reg(regs, "mscratch");
89	    v->medeleg  = find_reg(regs, "medeleg");
90	    v->mideleg  = find_reg(regs, "mideleg");
91	    v->mip      = find_reg(regs, "mip");
92	    v->mie      = find_reg(regs, "mie");
93	    v->mcycle   = find_reg(regs, "mcycle");
94	    v->minstret = find_reg(regs, "minstret");
95	    v->satp     = find_reg(regs, "satp");
96	
97	    char buf[16];
98	    for (int i = 0; i < HYBRID_PMP_CFG_NUM; i++) {
99	        g_snprintf(buf, sizeof(buf), "pmpcfg%d", i);
100	        v->pmpcfg[i] = find_reg(regs, buf);
101	    }
102	    for (int i = 0; i < HYBRID_PMP_ADDR_NUM; i++) {
103	        g_snprintf(buf, sizeof(buf), "pmpaddr%d", i);
104	        v->pmpaddr[i] = find_reg(regs, buf);
105	    }
106	
107	    v->vstart = find_reg(regs, "vstart");
108	    v->vtype  = find_reg(regs, "vtype");
109	    v->vl     = find_reg(regs, "vl");
110	    v->vlenb  = find_reg(regs, "vlenb");
111	    for (int i = 0; i < 32; i++) {
112	        g_snprintf(buf, sizeof(buf), "v%d", i);
113	        v->vreg[i] = find_reg(regs, buf);
114	    }
115	}
