117	static uint64_t read_reg64(struct qemu_plugin_register *h)
118	{
119	    if (!h) return 0;
120	    g_autoptr(GByteArray) buf = g_byte_array_new();
121	    int sz = qemu_plugin_read_register(h, buf);
122	    if (sz <= 0) return 0;
123	    uint64_t v = 0;
124	    memcpy(&v, buf->data, sz < 8 ? (size_t) sz : 8);
125	    return v;
126	}
