242	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
243	{
244	    (void) id;
245	    size_t n = qemu_plugin_tb_n_insns(tb);
246	    for (size_t i = 0; i < n; i++) {
247	        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);
248	        size_t sz = qemu_plugin_insn_size(insn);
249	        if (sz != 4) continue;
250	        uint32_t raw = 0;
251	        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
252	            continue;
253	        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
254	        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
255	        qemu_plugin_register_vcpu_insn_exec_cb(
256	            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS,
257	            (void *) (uintptr_t) kind);
258	    }
259	}
