261	QEMU_PLUGIN_EXPORT int qemu_plugin_install(qemu_plugin_id_t id,
262	                                           const qemu_info_t *info,
263	                                           int argc, char **argv)
264	{
265	    (void) info;
266	    for (int i = 0; i < argc; i++) {
267	        g_auto(GStrv) tok = g_strsplit(argv[i], "=", 2);
268	        if (g_strcmp0(tok[0], "outfile") == 0 && tok[1]) {
269	            outfile_path = g_strdup(tok[1]);
270	        } else {
271	            fprintf(stderr, "hybrid_handoff: unknown option: %s\n", argv[i]);
272	            return -1;
273	        }
274	    }
275	    if (!outfile_path) {
276	        fputs("hybrid_handoff: outfile=PATH is required\n", stderr);
277	        return -1;
278	    }
279	
280	    vcpu_state = qemu_plugin_scoreboard_new(sizeof(VcpuRegs));
281	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
282	    return 0;
283	}
