64	// Thrown by connect_loopback when the watched child exits before the
65	// gdbstub becomes reachable (typically: bad --qemu-binary path).
66	struct ChildExitedDuringConnect
67	{
68	  int status;
69	};
70	
71	inline auto connect_loopback(uint16_t port,
72	                             std::chrono::milliseconds timeout,
73	                             pid_t child_pid = -1) -> int
74	{
75	  const auto deadline = std::chrono::steady_clock::now() + timeout;
76	  while (std::chrono::steady_clock::now() < deadline) {
77	    const int s = ::socket(AF_INET, SOCK_STREAM, 0);
78	    if (s < 0)
79	      throw std::runtime_error("connect_loopback: socket");
80	    sockaddr_in addr{};
81	    addr.sin_family      = AF_INET;
82	    addr.sin_addr.s_addr = htonl(INADDR_LOOPBACK);
83	    addr.sin_port        = htons(port);
84	    if (::connect(s, reinterpret_cast<sockaddr*>(&addr), sizeof(addr)) == 0)
85	      return s;
86	    ::close(s);
87	    if (child_pid > 0) {
88	      int wstat = 0;
89	      if (::waitpid(child_pid, &wstat, WNOHANG) == child_pid) {
90	        int status = -1;
91	        if (WIFEXITED(wstat)) status = WEXITSTATUS(wstat);
92	        else if (WIFSIGNALED(wstat)) status = 128 + WTERMSIG(wstat);
93	        throw ChildExitedDuringConnect{status};
94	      }
95	    }
96	    std::this_thread::sleep_for(std::chrono::milliseconds(20));
97	  }
98	  throw std::runtime_error("connect_loopback: timed out waiting for QEMU "
99	                           "gdbstub");
100	}
