153	// Fetches a qXfer:features:read annex in full, looping while the stub
154	// answers with the 'm' (more) marker. QEMU's RISC-V CSR XML is ~6 KB and
155	// PacketSize is typically 1000 bytes, so several iterations are normal.
156	inline auto fetch_feature_xml(gdbstub::Session& sess, const std::string& annex)
157	  -> std::string
158	{
159	  std::string accum;
160	  std::size_t offset = 0;
161	  // Use a chunk size below the QEMU default PacketSize=1000. Asking for
162	  // 0x100 keeps each frame well under the wire limit even after the 'm'
163	  // marker and packet framing overhead.
164	  constexpr std::size_t kChunk = 0x100;
165	  while (true) {
166	    char buf[64];
167	    std::snprintf(buf, sizeof(buf), ":%zx,%zx", offset, kChunk);
168	    auto body = sess.send_command("qXfer:features:read:" + annex + buf);
169	    if (body.empty())
170	      throw std::runtime_error("qXfer empty reply for " + annex);
171	    const char marker = body.front();
172	    if (marker != 'l' && marker != 'm')
173	      throw std::runtime_error("qXfer non-l/m reply for " + annex + ": "
174	                               + std::string{marker});
175	    accum.append(body.substr(1));
176	    if (marker == 'l') return accum;
177	    offset += body.size() - 1;
178	  }
179	}
