181	// Walks target.xml and every <xi:include> annex, returning the merged
182	// register-name -> packet-number map.
183	inline auto discover_reg_map(gdbstub::Session& sess) -> gdbstub::RegMap
184	{
185	  gdbstub::RegMap map;
186	  const auto target_xml = fetch_feature_xml(sess, "target.xml");
187	  unsigned next = 0;
188	  for (const auto& annex : gdbstub::parse_target_xml(target_xml)) {
189	    const auto annex_xml = fetch_feature_xml(sess, annex);
190	    gdbstub::parse_feature_xml(annex_xml, map, next);
191	  }
192	  return map;
193	}
