122	  void handle_trans(tlm::tlm_generic_payload& trans)
123	  {
124	    const auto addr = trans.get_address();
125	    const auto len = trans.get_data_length();
126	    const auto buf = std::span{trans.get_data_ptr(), len};
127	    const auto offset = addr - region.base_address;
128	
129	    if (trans.is_read()) {
130	      spdlog::debug("sim_control: read, addr={:#x}, len={}", addr, len);
131	      return;
132	    }
133	
134	    spdlog::debug("sim_control: write, addr={:#x}, len={}", addr, len);
135	
136	    if (offset == 0 && len == 4) {
137	      handle_sim_command(unpack<uint32_t>(buf));
138	    } else if (offset == HTIF_PUTCHAR_OFFSET && len == 1) {
139	      std::putchar(buf[0]);
140	    } else if (offset == HTIF_CMD_OFFSET) {
141	      (len == 8) ? handle_htif_64bit_write(buf)
142	                 : handle_htif_32bit_low_write(buf);
143	    } else if (offset == HTIF_CMD_HIGH_OFFSET && len == 4) {
144	      handle_htif_32bit_high_write(buf);
145	    } else if (offset == INT_TRIGGER_OFFSET && len == 4) {
146	      auto val = unpack<uint32_t>(buf);
147	      spdlog::debug("sim_control: int_trigger = {:#x}", val);
148	      int_trigger.write(val);
149	      // clear the IRQ after one cycle
150	      if (val != 0) {
151	        wait(clk.posedge_event());
152	        int_trigger.write(0);
153	      }
154	    } else {
155	      spdlog::warn("sim_control: spurious write at {:#x}, length {}", addr,
156	                   len);
157	    }
158	  }
