160	  void handle_sim_command(uint32_t command)
161	  {
162	    spdlog::info("sim_control: received command {:#x}", command);
163	    switch (static_cast<SimCommand>(command)) {
164	    case SimCommand::NEWLINE:
165	      std::putchar('\n');
166	      break;
167	    case SimCommand::TEST_ILM:
168	      subport_test = SubPortTest::TEST_ILM;
169	      custom_master_sem.post();
170	      break;
171	    case SimCommand::TEST_DLM:
172	      subport_test = SubPortTest::TEST_DLM;
173	      custom_master_sem.post();
174	      break;
175	    case SimCommand::TEST_HVM:
176	      subport_test = SubPortTest::TEST_HVM;
177	      custom_master_sem.post();
178	      break;
179	    case SimCommand::PASSED:
180	    case SimCommand::FINISHED:
181	      spdlog::info("sim_control: Test PASSED");
182	      exits = 0;
183	      break;
184	    case SimCommand::SKIPPED:
185	      spdlog::info("sim_control: Test SKIPPED");
186	      exits = 0;
187	      break;
188	    case SimCommand::FAILED:
189	      spdlog::info("sim_control: Test FAILED");
190	      exits = 1;
191	      break;
192	    case SimCommand::WARNING:
193	      spdlog::warn("sim_control: Test WARNING");
194	      exits = 1;
195	      break;
196	    default:
197	      if (command < 256)
198	        exits = command;
199	      else
200	        spdlog::warn("sim_control: unknown command {:#x}", command);
201	      break;
202	    }
203	  }
204	
205	  template<typename T>
206	  static T unpack(const std::span<uint8_t>& buf)
207	  {
208	    T result = 0;
209	    for (size_t i = 0; i < sizeof(T); ++i)
210	      result |= static_cast<T>(buf[i]) << (i * 8);
211	    return result;
212	  }
213	
214	  void execute_htif_syscall()
215	  {
216	    command_t cmd(partial_htif_command);
217	    if (cmd.device() != 0 || cmd.cmd() != 0) {
218	      spdlog::warn("sim_control: unknown device: #{}", cmd.device());
219	      return;
220	    }
221	    dispatch(cmd);
222	    partial_htif_command = 0;
223	    htif_parts_received = 0;
224	  }
225	
226	  void handle_htif_64bit_write(const std::span<uint8_t>& buf)
227	  {
228	    command_t cmd(unpack<uint64_t>(buf));
229	    if (cmd.device() == 0 && cmd.cmd() == 0)
230	      dispatch(cmd);
231	    else
232	      spdlog::warn("sim_control: unknown device: #{}", cmd.device());
233	  }
234	
235	  void handle_htif_32bit_low_write(const std::span<uint8_t>& buf)
236	  {
237	    partial_htif_command |= unpack<uint32_t>(buf);
238	    if (++htif_parts_received == HTIF_32BIT_PARTS)
239	      execute_htif_syscall();
240	  }
241	
242	  void handle_htif_32bit_high_write(const std::span<uint8_t>& buf)
243	  {
244	    partial_htif_command |= static_cast<uint64_t>(unpack<uint32_t>(buf)) << 32;
245	    if (++htif_parts_received == HTIF_32BIT_PARTS)
246	      execute_htif_syscall();
247	  }
248	
249	  void dispatch(command_t cmd)
250	  {
251	    uint64_t syscall_args[MAGIC_MEM_SIZE];
252	    auto addr_offset = cmd.payload() - data_region.region.base_address;
253	    auto src = data_region.data.begin() + addr_offset;
254	
255	    std::copy(src, src + sizeof(syscall_args),
256	              reinterpret_cast<uint8_t*>(syscall_args));
257	
258	    spdlog::debug("sim_control: args: {:#x}, {:#x}, {:#x}, "
259	                  "{:#x}, {:#x}, {:#x}, {:#x}",
260	                  syscall_args[0], syscall_args[1], syscall_args[2],
261	                  syscall_args[3], syscall_args[4], syscall_args[5],
262	                  syscall_args[6]);
263	
264	    auto syscall_num = syscall_args[0];
265	    if (syscall_num >= SYSCALL_TABLE_SIZE || !sim_syscall_table[syscall_num]) {
266	      spdlog::critical("sim_control: invalid syscall number {}", syscall_num);
267	      syscall_args[0] = static_cast<uint64_t>(-1);
268	    } else {
269	      syscall_args[0] = (this->*sim_syscall_table[syscall_num])(
270	        syscall_args[1], syscall_args[2], syscall_args[3], syscall_args[4],
271	        syscall_args[5], syscall_args[6], syscall_args[7]);
272	    }
273	
274	    std::copy(reinterpret_cast<uint8_t*>(syscall_args),
275	              reinterpret_cast<uint8_t*>(syscall_args) + sizeof(syscall_args),
276	              src);
277	  }
278	};
